const SpotLightComp = 'spotLight' as any;
const HemisphereLightComp = 'hemisphereLight' as any;
const RectAreaLightComp = 'rectAreaLight' as any;
const LightProbeComp = 'lightProbe' as any;
const OrthographicCameraComp = 'orthographicCamera' as any;
const GroupComp = 'group' as any;
const MeshComp = 'mesh' as any;
const PlaneGeometryComp = 'planeGeometry' as any;
const MeshStandardMaterialComp = 'meshStandardMaterial' as any;
const ColorComp = 'color' as any;

/**
 * EffectsRenderer filters out disabled effects to avoid sending nulls to EffectComposer,
 * which can cause TypeScript and runtime issues.
 */
const EffectsRenderer: React.FC<{ effects: AppState['effects'] }> = ({ effects }) => {
  return (
    <EffectComposer multisampling={4}>
      {effects.smaa.enabled && <SMAA />}
      {effects.fxaa.enabled && <FXAA />}
      {effects.bloom.enabled && (
        <Bloom 
          luminanceThreshold={effects.bloom.threshold} 
          intensity={effects.bloom.intensity} 
          radius={effects.bloom.radius} 
          mipmapBlur 
        />
      )}
      {effects.glitch.enabled && (
        <Glitch 
          delay={effects.glitch.delay} 
          duration={effects.glitch.duration} 
          strength={effects.glitch.strength} 
          mode={effects.glitch.mode} 
        />
      )}
      {effects.dotScreen.enabled && (
        <DotScreen angle={effects.dotScreen.angle} scale={effects.dotScreen.scale} />
      )}
      {effects.pixelation.enabled && (
        <Pixelation granularity={effects.pixelation.granularity} />
      )}
      {effects.depthOfField.enabled && (
        <DepthOfField 
          focusDistance={effects.depthOfField.focusDistance} 
          focalLength={effects.depthOfField.focalLength} 
          bokehScale={effects.depthOfField.bokehScale} 
          height={effects.depthOfField.height} 
        />
      )}
      {effects.noise.enabled && <Noise opacity={effects.noise.opacity} />}
      {effects.vignette.enabled && (
        <Vignette offset={effects.vignette.offset} darkness={effects.vignette.darkness} />
      )}
      {effects.chromaticAberration.enabled && (
        <ChromaticAberration offset={new THREE.Vector2(...effects.chromaticAberration.offset)} />
      )}
      {effects.scanline.enabled && (
        <Scanline density={effects.scanline.density} opacity={effects.scanline.opacity} />
      )}
      {effects.ssao.enabled && (
        <SSAO samples={effects.ssao.samples} radius={effects.ssao.radius} intensity={effects.ssao.intensity} />
      )}
      {effects.outline.enabled && (
        <Outline 
          edgeStrength={effects.outline.edgeStrength} 
          pulseSpeed={effects.outline.pulseSpeed} 
          visibleEdgeColor={parseInt(effects.outline.visibleEdgeColor.replace('#', '0x'))} 
          hiddenEdgeColor={parseInt(effects.outline.hiddenEdgeColor.replace('#', '0x'))} 
        />
      )}
    </EffectComposer>
  );
};

/**
 * SceneController manages global scene attributes that are difficult to access via high-level props.
 * Specifically handles environmentIntensity for Three.js versions that support it (r163+).
 */
const SceneController: React.FC<{ environmentIntensity: number }> = ({ environmentIntensity }) => {
  const { scene } = useThree();
  useEffect(() => {
    // environmentIntensity is supported in modern Three.js; using ts-ignore for backward compatibility with older types if necessary
    // @ts-ignore
    if ('environmentIntensity' in scene) {
      // @ts-ignore
      scene.environmentIntensity = environmentIntensity;
    }
  }, [scene, environmentIntensity]);
  return null;
};

const DynamicLight: React.FC<{ light: LightSettings, globalShowHelpers: boolean }> = ({ light, globalShowHelpers }) => {
  const lightRef = useRef<any>(null);

  // Cast helper constructors to any to resolve argument mapping issues in useHelper types
  useHelper(globalShowHelpers && light.type === 'directional' ? lightRef : null, THREE.DirectionalLightHelper as any, 1, 'white');
  useHelper(globalShowHelpers && light.type === 'point' ? lightRef : null, THREE.PointLightHelper as any, 0.5, light.color);
  useHelper(globalShowHelpers && light.type === 'spot' ? lightRef : null, THREE.SpotLightHelper as any, 'white');
  useHelper(globalShowHelpers && light.type === 'hemisphere' ? lightRef : null, THREE.HemisphereLightHelper as any, 2, light.color);
  useHelper(globalShowHelpers && light.type === 'rectArea' ? lightRef : null, RectAreaLightHelper as any, 'white');
  useHelper(globalShowHelpers && light.showShadowHelper && lightRef.current?.shadow?.camera ? lightRef : null, THREE.CameraHelper as any);

  switch (light.type) {
    case 'directional':
      return (
        <DirectionalLightComp ref={lightRef} position={light.position} intensity={light.intensity} color={light.color} castShadow={light.castShadow} visible={light.visible}>
          <OrthographicCameraComp attach="shadow-camera" args={[-10, 10, 10, -10, 0.5, 30]} />
        </DirectionalLightComp>
      );
    case 'point':
      return <PointLightComp ref={lightRef} position={light.position} intensity={light.intensity} color={light.color} castShadow={light.castShadow} visible={light.visible} />;
    case 'spot':
      return <SpotLightComp ref={lightRef} position={light.position} intensity={light.intensity} color={light.color} castShadow={light.castShadow} visible={light.visible} angle={0.3} penumbra={1} />;
    case 'hemisphere':
      return <HemisphereLightComp ref={lightRef} position={light.position} args={[light.color, light.groundColor, light.intensity]} visible={light.visible} />;
    case 'rectArea':
      return <RectAreaLightComp ref={lightRef} position={light.position} rotation={light.rotation || [0, 0, 0]} intensity={light.intensity} width={light.width || 4} height={light.height || 4} color={light.color} visible={light.visible} />;
    case 'ambient':
      return <AmbientLightComp intensity={light.intensity} color={light.color} visible={light.visible} />;
    case 'lightProbe':
      return <LightProbeComp ref={lightRef} intensity={light.intensity} visible={light.visible} />;
    default: return null;
  }
};

export default function App() {
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const [activeTab, setActiveTab] = useState<TabType>('settings');
  const [customModel, setCustomModel] = useState<string | null>(null);
  const [isPending, startTransition] = useTransition();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const updateState = useCallback(<K extends keyof AppState, S extends keyof AppState[K]>(category: K, key: S, value: AppState[K][S]) => {
    setState(prev => ({ ...prev, [category]: { ...prev[category], [key]: value } }));
  }, []);

  const updateEffect = useCallback(<S extends keyof AppState['effects'], P extends keyof AppState['effects'][S]>(effect: S, prop: P, value: any) => {
    setState(prev => ({
      ...prev,
      effects: {
        ...prev.effects,
        [effect]: { ...prev.effects[effect], [prop]: value }
      }
    }));
  }, []);

  // Fix: Capture mat in a local variable to ensure TypeScript flow analysis recognizes it as an object for spreading
  const updateMaterial = useCallback(<S extends keyof MaterialSettings>(key: S, value: MaterialSettings[S]) => {
    setState(prev => {
      const currentId = prev.selectedMaterialId;
      const mat = prev.materials[currentId];
      if (!mat) return prev;
      return {
        ...prev,
        materials: { 
          ...prev.materials, 
          [currentId]: { ...mat, [key]: value } 
        }
      };
    });
  }, []);

  const setTopState = useCallback(<K extends keyof AppState>(key: K, value: AppState[K]) => {
    setState(prev => ({ ...prev, [key]: value }));
  }, []);

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (customModel) URL.revokeObjectURL(customModel);
      const url = URL.createObjectURL(file);
      startTransition(() => {
        setCustomModel(url);
        setState(prev => ({ ...prev, scene: { ...prev.scene, modelType: 'custom' } }));
      });
    }
  };

  const onMaterialsDiscovered = useCallback((discoveredMaterials: string[]) => {
    setState(prev => {
      const newMaterials = { ...prev.materials };
      let firstId = prev.selectedMaterialId;
      discoveredMaterials.forEach((name, index) => {
        const id = `mat-${name || index}`;
        if (!newMaterials[id]) newMaterials[id] = createDefaultMaterial(id, name || `Material ${index + 1}`);
        if (index === 0 && (prev.selectedMaterialId === 'default-material' || !prev.materials[prev.selectedMaterialId])) firstId = id;
      });
      return { ...prev, materials: newMaterials, selectedMaterialId: firstId };
    });
  }, []);

  const handleUpdateLights = (lights: LightSettings[]) => setState(prev => ({ ...prev, lights }));

  const toneMappingValue = useMemo(() => {
    switch(state.scene.toneMapping) {
      case 'Linear': return THREE.LinearToneMapping;
      case 'Reinhard': return THREE.ReinhardToneMapping;
      case 'Cineon': return THREE.CineonToneMapping;
      case 'ACESFilmic': return THREE.ACESFilmicToneMapping;
      default: return THREE.NoToneMapping;
    }
  }, [state.scene.toneMapping]);

  return (
    <div className="flex h-screen w-full bg-slate-950 text-slate-100 overflow-hidden font-sans">
      <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept=".glb,.gltf,.obj" />
      <main className="relative flex-1 bg-black">
        {isPending && <div className="absolute inset-0 flex items-center justify-center bg-black/40 backdrop-blur-sm z-50 pointer-events-none"><Loader2 className="w-10 h-10 text-blue-500 animate-spin" /></div>}
        <Canvas 
          shadows={{ type: THREE.PCFSoftShadowMap }} 
          dpr={[1, 2]} 
          gl={{ 
            antialias: true, 
            alpha: false, 
            stencil: false,
            toneMapping: toneMappingValue,
            toneMappingExposure: state.scene.exposure
          }}
        >
          <ColorComp attach="background" args={[state.scene.background]} />
          <PerspectiveCamera makeDefault position={[4, 3, 4]} fov={state.scene.fov} />
          <OrbitControls makeDefault autoRotate={state.scene.autoRotate} autoRotateSpeed={0.5} enableDamping />

          <AmbientLightComp intensity={state.scene.ambientIntensity} />
          {state.lights.map((light) => <DynamicLight key={light.id} light={light} globalShowHelpers={state.scene.showHelpers} />)}

          {state.scene.environmentPreset !== 'none' && (
            <Environment 
              preset={state.scene.environmentPreset as any} 
              blur={state.scene.environmentBlur} 
            />
          )}

          <SceneController environmentIntensity={state.scene.environmentIntensity} />

          <GroupComp position={[0, 0, 0]}>
            <Float speed={1.5} rotationIntensity={0.2} floatIntensity={state.scene.showPlane ? 0 : 0.5}>
              <Suspense fallback={null}>
                <SceneModel 
                  materials={state.materials} 
                  modelType={state.scene.modelType} 
                  customUrl={customModel} 
                  override={state.scene.overrideMaterials} 
                  onMaterialsFound={onMaterialsDiscovered} 
                />
              </Suspense>
            </Float>
          </GroupComp>

          {state.scene.showPlane && (
            <MeshComp rotation={[-Math.PI / 2, 0, 0]} position={[0, -1.0, 0]} receiveShadow>
              <PlaneGeometryComp args={[100, 100]} />
              <MeshStandardMaterialComp color={state.scene.planeColor} roughness={state.scene.planeRoughness} metalness={0.1} transparent={state.scene.planeOpacity < 1} opacity={state.scene.planeOpacity} />
            </MeshComp>
          )}

          {state.scene.contactShadows && <ContactShadows position={[0, -0.99, 0]} opacity={state.scene.shadowOpacity} scale={15} blur={state.scene.shadowBlur} far={3} />}
          {state.scene.gridHelper && state.scene.showPlane && <Grid position={[0, -0.995, 0]} args={[20, 20]} sectionColor="#475569" cellColor="#334155" fadeDistance={25} infiniteGrid />}

          <EffectsRenderer effects={state.effects} />

          <BakeShadows />
        </Canvas>

        <div className="absolute top-6 left-6 pointer-events-none select-none">
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 via-indigo-400 to-emerald-400 tracking-tight">Three.js Studio Pro</h1>
          <p className="text-slate-500 text-[10px] tracking-[0.3em] uppercase mt-1 flex items-center gap-2">
            <Package size={10} /> {state.scene.modelType === 'custom' ? 'External Asset' : 'Built-in Geometry'}
          </p>
        </div>

        <button 
          onClick={() => fileInputRef.current?.click()} 
          className="absolute bottom-6 left-6 p-4 bg-blue-600 hover:bg-blue-500 rounded-full shadow-[0_0_20px_rgba(37,99,235,0.4)] transition-all hover:scale-110 active:scale-95 group cursor-pointer" 
          title="Upload GLB/OBJ"
        >
          <Upload size={24} className="text-white" />
        </button>
      </main>

      <div className="w-[440px] h-full bg-slate-900/98 backdrop-blur-xl border-l border-slate-800 flex flex-col shadow-2xl z-10 overflow-hidden">
        <div className="flex border-b border-slate-800">
          <button onClick={() => setActiveTab('settings')} className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 cursor-pointer ${activeTab === 'settings' ? 'text-blue-400 border-blue-500 bg-slate-800/30' : 'text-slate-50 border-transparent hover:text-slate-300'}`}><Settings2 size={16} /><span className="text-[11px] font-bold uppercase tracking-widest">Props</span></button>
          <button onClick={() => setActiveTab('lights')} className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 cursor-pointer ${activeTab === 'lights' ? 'text-amber-400 border-amber-500 bg-slate-800/30' : 'text-slate-500 border-transparent hover:text-slate-300'}`}><Lightbulb size={16} /><span className="text-[11px] font-bold uppercase tracking-widest">Lights</span></button>
          <button onClick={() => setActiveTab('effects')} className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 cursor-pointer ${activeTab === 'effects' ? 'text-purple-400 border-purple-500 bg-slate-800/30' : 'text-slate-500 border-transparent hover:text-slate-300'}`}><Wand2 size={16} /><span className="text-[11px] font-bold uppercase tracking-widest">FX</span></button>
          <button onClick={() => setActiveTab('code')} className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 cursor-pointer ${activeTab === 'code' ? 'text-emerald-400 border-emerald-500 bg-slate-800/30' : 'text-slate-500 border-transparent hover:text-slate-300'}`}><Code size={16} /><span className="text-[11px] font-bold uppercase tracking-widest">Code</span></button>
        </div>
        <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
          {activeTab === 'settings' && <Sidebar state={state} updateState={updateState} updateMaterial={updateMaterial} setSelectedMaterialId={(id) => setTopState('selectedMaterialId', id)} />}
          {activeTab === 'lights' && <LightsPanel lights={state.lights} onUpdateLights={handleUpdateLights} showHelpers={state.scene.showHelpers} onToggleHelpers={(v) => updateState('scene', 'showHelpers', v)} sceneAmbient={state.scene.ambientIntensity} onUpdateSceneAmbient={(v) => updateState('scene', 'ambientIntensity', v)} envPreset={state.scene.environmentPreset} onUpdateEnvPreset={(v) => updateState('scene', 'environmentPreset', v)} />}
          {activeTab === 'effects' && <EffectsPanel effects={state.effects} onUpdateEffect={updateEffect} />}
          {activeTab === 'code' && <CodePanel state={state} />}
        </div>
      </div>
    </div>
  );
}

export type MaterialType = 'basic' | 'phong' | 'standard' | 'physical' | 'lambert' | 'toon' | 'normal' | 'depth' | 'matcap';
export type ModelType = 'icosahedron' | 'sphere' | 'box' | 'torus' | 'cylinder' | 'cone' | 'knot' | 'custom';
export type LightType = 'ambient' | 'directional' | 'point' | 'spot' | 'hemisphere' | 'rectArea' | 'lightProbe';
export type ViewMode = 'material' | 'wireframe';

export interface EffectSettings {
  enabled: boolean;
  [key: string]: any;
}

export interface LightSettings {
  id: string;
  type: LightType;
  color: string;
  groundColor?: string; // For Hemisphere
  intensity: number;
  position: [number, number, number];
  rotation?: [number, number, number]; // For RectArea
  width?: number; // For RectArea
  height?: number; // For RectArea
  castShadow: boolean;
  visible: boolean; // Controls if the light actually illuminates
  showShadowHelper?: boolean; // Controls if shadow frustum is visible
}

export interface MaterialSettings {
  id: string;
  name: string;
  type: MaterialType;
  color: string;
  emissive: string;
  emissiveIntensity: number;
  metalness: number;
  roughness: number;
  wireframe: boolean;
  opacity: number;
  transparent: boolean;
  envMapIntensity: number;
  clearcoat: number;
  clearcoatRoughness: number;
  transmission: number;
  thickness: number;
  ior: number;
  specularIntensity: number;
  shininess: number;
  specular: string;
  depthPacking: boolean;
  matcapUrl?: string;
}

export interface SceneSettings {
  exposure: number;
  background: string;
  autoRotate: boolean;
  gridHelper: boolean;
  ambientIntensity: number;
  contactShadows: boolean;
  shadowOpacity: number;
  shadowBlur: number;
  showPlane: boolean;
  planeColor: string;
  planeRoughness: number;
  planeOpacity: number;
  modelType: ModelType;
  overrideMaterials: boolean;
  showHelpers: boolean;
  environmentPreset: string;
  viewMode: ViewMode;
}

export interface AppState {
  materials: Record<string, MaterialSettings>;
  selectedMaterialId: string;
  scene: SceneSettings;
  lights: LightSettings[];
  effects: {
    bloom: EffectSettings;
    glitch: EffectSettings;
    dotScreen: EffectSettings;
    pixelation: EffectSettings;
    depthOfField: EffectSettings;
    noise: EffectSettings;
    vignette: EffectSettings;
    chromaticAberration: EffectSettings;
    scanline: EffectSettings;
    smaa: EffectSettings;
    fxaa: EffectSettings;
    ssao: EffectSettings;
    outline: EffectSettings;
  };
}

export type TabType = 'settings' | 'lights' | 'effects' | 'code';

import React, { useMemo, useEffect } from 'react';
import * as THREE from 'three';
import { useGLTF, useMatcapTexture } from '@react-three/drei';
import { MaterialSettings, ModelType, ViewMode } from '../types';

interface SceneModelProps {
  materials: Record<string, MaterialSettings>;
  modelType: ModelType;
  customUrl: string | null;
  override: boolean;
  viewMode: ViewMode;
  onMaterialsFound?: (names: string[]) => void;
}

const MeshComp = 'mesh' as any;
const Primitive = 'primitive' as any;
const MeshStandardMaterial = 'meshStandardMaterial' as any;

const wireframeMaterial = new THREE.MeshBasicMaterial({ color: '#4ade80', wireframe: true });

/**
 * Separated component to handle custom model loading.
 */
const CustomModelInstance = ({ 
  url, 
  onMaterialsFound, 
  nativeMaterials, 
  override,
  viewMode
}: { 
  url: string, 
  onMaterialsFound?: (names: string[]) => void,
  nativeMaterials: Record<string, THREE.Material>,
  override: boolean,
  viewMode: ViewMode
}) => {
  const { scene } = useGLTF(url) as any;

  useEffect(() => {
    if (scene && onMaterialsFound) {
      const foundNames = new Set<string>();
      scene.traverse((child: any) => {
        if (child.isMesh) {
          const mats = Array.isArray(child.material) ? child.material : [child.material];
          mats.forEach((m: any) => {
            if (m && m.name) foundNames.add(m.name);
          });
        }
      });
      if (foundNames.size > 0) {
        onMaterialsFound(Array.from(foundNames));
      }
    }
  }, [scene, onMaterialsFound]);

  useEffect(() => {
    if (scene) {
      scene.traverse((child: any) => {
        if (child.isMesh) {
          child.castShadow = viewMode === 'material';
          child.receiveShadow = viewMode === 'material';

          if (viewMode === 'wireframe') {
            child.material = wireframeMaterial;
          } else if (override) {
            if (Array.isArray(child.material)) {
              child.material = child.material.map((orig: any) => {
                const name = orig?.name;
                return (name && nativeMaterials[name]) || orig;
              });
            } else if (child.material) {
              const name = child.material.name;
              const matched = name && nativeMaterials[name];
              if (matched) child.material = matched;
            }
          }
        }
      });
    }
  }, [scene, nativeMaterials, override, viewMode]);

  return <Primitive object={scene} scale={2} />;
};

const SceneModel: React.FC<SceneModelProps> = ({ materials, modelType, customUrl, override, viewMode, onMaterialsFound }) => {
  const [matcapTexture] = useMatcapTexture(0, 256);

  const createMaterial = (settings: MaterialSettings) => {
    if (viewMode === 'wireframe') return wireframeMaterial;

    const isTransparent = settings.opacity < 1 || settings.transmission > 0 || settings.transparent;
    const baseProps: any = {
      color: new THREE.Color(settings.color),
      wireframe: settings.wireframe,
      transparent: isTransparent,
      opacity: settings.opacity,
      side: THREE.DoubleSide,
      name: settings.name
    };

    if (['phong', 'lambert', 'standard', 'physical'].includes(settings.type)) {
      baseProps.emissive = new THREE.Color(settings.emissive);
      baseProps.emissiveIntensity = settings.emissiveIntensity;
    }

    let material: THREE.Material;
    switch (settings.type) {
      case 'basic': material = new THREE.MeshBasicMaterial(baseProps); break;
      case 'lambert': material = new THREE.MeshLambertMaterial(baseProps); break;
      case 'phong': material = new THREE.MeshPhongMaterial({ ...baseProps, specular: new THREE.Color(settings.specular), shininess: settings.shininess }); break;
      case 'toon': material = new THREE.MeshToonMaterial(baseProps); break;
      case 'normal': material = new THREE.MeshNormalMaterial({ wireframe: settings.wireframe, name: settings.name }); break;
      case 'depth': material = new THREE.MeshDepthMaterial({ wireframe: settings.wireframe, name: settings.name }); break;
      case 'matcap': material = new THREE.MeshMatcapMaterial({ ...baseProps, matcap: matcapTexture }); break;
      case 'physical': material = new THREE.MeshPhysicalMaterial({
        ...baseProps,
        metalness: settings.metalness,
        roughness: settings.roughness,
        clearcoat: settings.clearcoat,
        clearcoatRoughness: settings.clearcoatRoughness,
        transmission: settings.transmission,
        thickness: settings.thickness,
        ior: settings.ior,
        envMapIntensity: settings.envMapIntensity
      }); break;
      case 'standard':
      default:
        material = new THREE.MeshStandardMaterial({ ...baseProps, metalness: settings.metalness, roughness: settings.roughness, envMapIntensity: settings.envMapIntensity });
    }
    return material;
  };

  const nativeMaterials = useMemo(() => {
    const map: Record<string, THREE.Material> = {};
    (Object.entries(materials) as [string, MaterialSettings][]).forEach(([_, settings]) => {
      map[settings.name] = createMaterial(settings);
    });
    return map;
  }, [materials, matcapTexture, viewMode]);

  if (modelType === 'custom' && customUrl) {
    return (
      <CustomModelInstance 
        url={customUrl} 
        onMaterialsFound={onMaterialsFound}
        nativeMaterials={nativeMaterials}
        override={override}
        viewMode={viewMode}
      />
    );
  }

  const activeSettings = (Object.values(materials)[0] || materials['default-material']) as MaterialSettings | undefined;

  return (
    <MeshComp castShadow={viewMode === 'material'} receiveShadow={viewMode === 'material'}>
      {modelType === 'box' && <boxGeometry args={[1, 1, 1]} />}
      {modelType === 'sphere' && <sphereGeometry args={[0.7, 64, 64]} />}
      {modelType === 'torus' && <torusGeometry args={[0.5, 0.2, 32, 100]} />}
      {modelType === 'cylinder' && <cylinderGeometry args={[0.5, 0.5, 1, 32]} />}
      {modelType === 'cone' && <coneGeometry args={[0.5, 1, 32]} />}
      {modelType === 'knot' && <torusKnotGeometry args={[0.4, 0.15, 128, 32]} />}
      {modelType === 'icosahedron' && <icosahedronGeometry args={[0.8, 15]} />}

      {viewMode === 'wireframe' ? (
        <Primitive object={wireframeMaterial} attach="material" />
      ) : activeSettings ? (
        <Primitive object={createMaterial(activeSettings)} attach="material" />
      ) : (
        <MeshStandardMaterial color="#3b82f6" />
      )}
    </MeshComp>
  );
};

export default SceneModel;

import React, { useState, useCallback, useRef, Suspense, useTransition, useEffect } from 'react';
import { Canvas } from '@react-three/fiber';
import * as THREE from 'three';
import { 
  OrbitControls, 
  PerspectiveCamera, 
  Grid, 
  Environment,
  ContactShadows,
  Float,
  BakeShadows,
  useHelper
} from '@react-three/drei';
import { RectAreaLightUniformsLib } from 'three/examples/jsm/lights/RectAreaLightUniformsLib';
import { RectAreaLightHelper } from 'three/examples/jsm/helpers/RectAreaLightHelper';
import { 
  EffectComposer, 
  Bloom, 
  Glitch, 
  DotScreen, 
  Pixelation, 
  DepthOfField, 
  Noise, 
  Vignette, 
  ChromaticAberration, 
  SMAA, 
  FXAA, 
  SSAO,
  Outline,
  Scanline
} from '@react-three/postprocessing';
import { Settings2, Code, Upload, Loader2, Package, Lightbulb, Wand2 } from 'lucide-react';
import { INITIAL_STATE, createDefaultMaterial } from './constants';
import { AppState, TabType, LightSettings, MaterialSettings } from './types';

// Sub-components
import Sidebar from './components/Sidebar';
import CodePanel from './components/CodePanel';
import SceneModel from './components/SceneModel';
import LightsPanel from './components/LightsPanel';
import EffectsPanel from './components/EffectsPanel';

// Initialize RectAreaLight uniforms
RectAreaLightUniformsLib.init();

const AmbientLightComp = 'ambientLight' as any;
const DirectionalLightComp = 'directionalLight' as any;
const PointLightComp = 'pointLight' as any;
const SpotLightComp = 'spotLight' as any;
const HemisphereLightComp = 'hemisphereLight' as any;
const RectAreaLightComp = 'rectAreaLight' as any;
const LightProbeComp = 'lightProbe' as any;
const OrthographicCameraComp = 'orthographicCamera' as any;
const GroupComp = 'group' as any;
const MeshComp = 'mesh' as any;
const PlaneGeometryComp = 'planeGeometry' as any;
const MeshStandardMaterialComp = 'meshStandardMaterial' as any;
const ColorComp = 'color' as any;

const DynamicLight: React.FC<{ light: LightSettings, globalShowHelpers: boolean }> = ({ light, globalShowHelpers }) => {
  const lightRef = useRef<any>(null);
  useHelper(globalShowHelpers && light.type === 'directional' ? lightRef : null, THREE.DirectionalLightHelper, 1, 'white');
  useHelper(globalShowHelpers && light.type === 'point' ? lightRef : null, THREE.PointLightHelper, 0.5, light.color);
  useHelper(globalShowHelpers && light.type === 'spot' ? lightRef : null, THREE.SpotLightHelper, 'white');
  useHelper(globalShowHelpers && light.type === 'hemisphere' ? lightRef : null, THREE.HemisphereLightHelper, 2, light.color);
  useHelper(globalShowHelpers && light.type === 'rectArea' ? lightRef : null, RectAreaLightHelper as any, 'white');
  useHelper(globalShowHelpers && light.showShadowHelper && lightRef.current?.shadow?.camera ? lightRef : null, THREE.CameraHelper);

  switch (light.type) {
    case 'directional':
      return (
        <DirectionalLightComp ref={lightRef} position={light.position} intensity={light.intensity} color={light.color} castShadow={light.castShadow} visible={light.visible}>
          <OrthographicCameraComp attach="shadow-camera" args={[-10, 10, 10, -10, 0.5, 30]} />
        </DirectionalLightComp>
      );
    case 'point':
      return <PointLightComp ref={lightRef} position={light.position} intensity={light.intensity} color={light.color} castShadow={light.castShadow} visible={light.visible} />;
    case 'spot':
      return <SpotLightComp ref={lightRef} position={light.position} intensity={light.intensity} color={light.color} castShadow={light.castShadow} visible={light.visible} angle={0.3} penumbra={1} />;
    case 'hemisphere':
      return <HemisphereLightComp ref={lightRef} position={light.position} args={[light.color, light.groundColor, light.intensity]} visible={light.visible} />;
    case 'rectArea':
      return <RectAreaLightComp ref={lightRef} position={light.position} rotation={light.rotation || [0, 0, 0]} intensity={light.intensity} width={light.width || 4} height={light.height || 4} color={light.color} visible={light.visible} />;
    case 'ambient':
      return <AmbientLightComp intensity={light.intensity} color={light.color} visible={light.visible} />;
    case 'lightProbe':
      return <LightProbeComp ref={lightRef} intensity={light.intensity} visible={light.visible} />;
    default: return null;
  }
};

export default function App() {
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const [activeTab, setActiveTab] = useState<TabType>('settings');
  const [customModel, setCustomModel] = useState<string | null>(null);
  const [isPending, startTransition] = useTransition();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const updateState = useCallback(<K extends keyof AppState, S extends keyof AppState[K]>(category: K, key: S, value: AppState[K][S]) => {
    setState(prev => ({ ...prev, [category]: { ...prev[category], [key]: value } }));
  }, []);

  const updateEffect = useCallback(<S extends keyof AppState['effects'], P extends keyof AppState['effects'][S]>(effect: S, prop: P, value: any) => {
    setState(prev => ({
      ...prev,
      effects: {
        ...prev.effects,
        [effect]: { ...prev.effects[effect], [prop]: value }
      }
    }));
  }, []);

  const updateMaterial = useCallback(<S extends keyof MaterialSettings>(key: S, value: MaterialSettings[S]) => {
    setState(prev => {
      const currentId = prev.selectedMaterialId;
      if (!prev.materials[currentId]) return prev;
      return {
        ...prev,
        materials: { ...prev.materials, [currentId]: { ...prev.materials[currentId], [key]: value } }
      };
    });
  }, []);

  const setTopState = useCallback(<K extends keyof AppState>(key: K, value: AppState[K]) => {
    setState(prev => ({ ...prev, [key]: value }));
  }, []);

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (customModel) URL.revokeObjectURL(customModel);
      const url = URL.createObjectURL(file);
      startTransition(() => {
        setCustomModel(url);
        setState(prev => ({ ...prev, scene: { ...prev.scene, modelType: 'custom' } }));
      });
    }
  };

  const onMaterialsDiscovered = useCallback((discoveredMaterials: string[]) => {
    setState(prev => {
      const newMaterials = { ...prev.materials };
      let firstId = prev.selectedMaterialId;
      discoveredMaterials.forEach((name, index) => {
        const id = `mat-${name || index}`;
        if (!newMaterials[id]) newMaterials[id] = createDefaultMaterial(id, name || `Material ${index + 1}`);
        if (index === 0 && (prev.selectedMaterialId === 'default-material' || !prev.materials[prev.selectedMaterialId])) firstId = id;
      });
      return { ...prev, materials: newMaterials, selectedMaterialId: firstId };
    });
  }, []);

  const handleUpdateLights = (lights: LightSettings[]) => setState(prev => ({ ...prev, lights }));

  return (
    <div className="flex h-screen w-full bg-slate-950 text-slate-100 overflow-hidden font-sans">
      <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept=".glb,.gltf,.obj" />
      <main className="relative flex-1 bg-black">
        {isPending && <div className="absolute inset-0 flex items-center justify-center bg-black/40 backdrop-blur-sm z-50 pointer-events-none"><Loader2 className="w-10 h-10 text-blue-500 animate-spin" /></div>}
        <Canvas shadows={{ type: THREE.PCFSoftShadowMap }} dpr={[1, 2]} gl={{ antialias: true, alpha: false, stencil: false }}>
          <ColorComp attach="background" args={[state.scene.background]} />
          <PerspectiveCamera makeDefault position={[4, 3, 4]} fov={50} />
          <OrbitControls makeDefault autoRotate={state.scene.autoRotate} autoRotateSpeed={0.5} enableDamping />
          <AmbientLightComp intensity={state.scene.ambientIntensity} />
          {state.lights.map((light) => <DynamicLight key={light.id} light={light} globalShowHelpers={state.scene.showHelpers} />)}
          {state.scene.environmentPreset !== 'none' && <Environment preset={state.scene.environmentPreset as any} />}
          <GroupComp position={[0, 0, 0]}>
            <Float speed={1.5} rotationIntensity={0.2} floatIntensity={state.scene.showPlane ? 0 : 0.5}>
              <Suspense fallback={null}>
                <SceneModel materials={state.materials} modelType={state.scene.modelType} customUrl={customModel} override={state.scene.overrideMaterials} viewMode={state.scene.viewMode} onMaterialsFound={onMaterialsDiscovered} />
              </Suspense>
            </Float>
          </GroupComp>
          {state.scene.showPlane && (
            <MeshComp rotation={[-Math.PI / 2, 0, 0]} position={[0, -1.0, 0]} receiveShadow>
              <PlaneGeometryComp args={[100, 100]} />
              <MeshStandardMaterialComp color={state.scene.planeColor} roughness={state.scene.planeRoughness} metalness={0.1} transparent={state.scene.planeOpacity < 1} opacity={state.scene.planeOpacity} />
            </MeshComp>
          )}
          {state.scene.contactShadows && <ContactShadows position={[0, -0.99, 0]} opacity={state.scene.shadowOpacity} scale={15} blur={state.scene.shadowBlur} far={3} />}
          {state.scene.gridHelper && state.scene.showPlane && <Grid position={[0, -0.995, 0]} args={[20, 20]} sectionColor="#cbd5e1" cellColor="#94a3b8" fadeDistance={25} infiniteGrid />}
          <EffectComposer multisampling={4}>
            {state.effects.smaa.enabled && <SMAA />}
            {state.effects.fxaa.enabled && <FXAA />}
            {state.effects.bloom.enabled && <Bloom luminanceThreshold={state.effects.bloom.threshold} intensity={state.effects.bloom.intensity} radius={state.effects.bloom.radius} mipmapBlur />}
            {state.effects.glitch.enabled && <Glitch delay={state.effects.glitch.delay} duration={state.effects.glitch.duration} strength={state.effects.glitch.strength} mode={state.effects.glitch.mode} />}
            {state.effects.dotScreen.enabled && <DotScreen angle={state.effects.dotScreen.angle} scale={state.effects.dotScreen.scale} />}
            {state.effects.pixelation.enabled && <Pixelation granularity={state.effects.pixelation.granularity} />}
            {state.effects.depthOfField.enabled && <DepthOfField focusDistance={state.effects.depthOfField.focusDistance} focalLength={state.effects.depthOfField.focalLength} bokehScale={state.effects.depthOfField.bokehScale} height={state.effects.depthOfField.height} />}
            {state.effects.noise.enabled && <Noise opacity={state.effects.noise.opacity} />}
            {state.effects.vignette.enabled && <Vignette offset={state.effects.vignette.offset} darkness={state.effects.vignette.darkness} />}
            {state.effects.chromaticAberration.enabled && <ChromaticAberration offset={new THREE.Vector2(...state.effects.chromaticAberration.offset)} />}
            {state.effects.scanline.enabled && <Scanline density={state.effects.scanline.density} opacity={state.effects.scanline.opacity} />}
            {state.effects.ssao.enabled && <SSAO samples={state.effects.ssao.samples} radius={state.effects.ssao.radius} intensity={state.effects.ssao.intensity} />}
            {state.effects.outline.enabled && <Outline edgeStrength={state.effects.outline.edgeStrength} pulseSpeed={state.effects.outline.pulseSpeed} visibleEdgeColor={parseInt(state.effects.outline.visibleEdgeColor.replace('#', '0x'))} hiddenEdgeColor={parseInt(state.effects.outline.hiddenEdgeColor.replace('#', '0x'))} />}
          </EffectComposer>
          <BakeShadows />
        </Canvas>
        <div className="absolute top-6 left-6 pointer-events-none select-none">
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 via-indigo-400 to-emerald-400">Three.js Master Control</h1>
          <p className="text-slate-500 text-[10px] tracking-[0.3em] uppercase mt-1 flex items-center gap-2"><Package size={10} /> {state.scene.modelType === 'custom' ? 'Complex Multi-Mesh Asset' : 'Internal Geometry'}</p>
        </div>
        <button onClick={() => fileInputRef.current?.click()} className="absolute bottom-6 left-6 p-4 bg-blue-600 hover:bg-blue-500 rounded-full shadow-[0_0_20px_rgba(37,99,235,0.4)] transition-all hover:scale-110 active:scale-95 group cursor-pointer" title="Upload GLB/OBJ"><Upload size={24} className="text-white" /></button>
      </main>
      <div className="w-[440px] h-full bg-slate-900/98 backdrop-blur-xl border-l border-slate-800 flex flex-col shadow-2xl z-10 overflow-hidden">
        <div className="flex border-b border-slate-800">
          <button onClick={() => setActiveTab('settings')} className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 cursor-pointer ${activeTab === 'settings' ? 'text-blue-400 border-blue-500 bg-slate-800/30' : 'text-slate-50 border-transparent hover:text-slate-300'}`}><Settings2 size={16} /><span className="text-[11px] font-bold uppercase tracking-widest">Props</span></button>
          <button onClick={() => setActiveTab('lights')} className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 cursor-pointer ${activeTab === 'lights' ? 'text-amber-400 border-amber-500 bg-slate-800/30' : 'text-slate-500 border-transparent hover:text-slate-300'}`}><Lightbulb size={16} /><span className="text-[11px] font-bold uppercase tracking-widest">Lights</span></button>
          <button onClick={() => setActiveTab('effects')} className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 cursor-pointer ${activeTab === 'effects' ? 'text-purple-400 border-purple-500 bg-slate-800/30' : 'text-slate-500 border-transparent hover:text-slate-300'}`}><Wand2 size={16} /><span className="text-[11px] font-bold uppercase tracking-widest">FX</span></button>
          <button onClick={() => setActiveTab('code')} className={`flex-1 py-5 transition-all duration-200 border-b-2 flex items-center justify-center gap-2 cursor-pointer ${activeTab === 'code' ? 'text-emerald-400 border-emerald-500 bg-slate-800/30' : 'text-slate-500 border-transparent hover:text-slate-300'}`}><Code size={16} /><span className="text-[11px] font-bold uppercase tracking-widest">Code</span></button>
        </div>
        <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
          {activeTab === 'settings' && <Sidebar state={state} updateState={updateState} updateMaterial={updateMaterial} setSelectedMaterialId={(id) => setTopState('selectedMaterialId', id)} />}
          {activeTab === 'lights' && <LightsPanel lights={state.lights} onUpdateLights={handleUpdateLights} showHelpers={state.scene.showHelpers} onToggleHelpers={(v) => updateState('scene', 'showHelpers', v)} sceneAmbient={state.scene.ambientIntensity} onUpdateSceneAmbient={(v) => updateState('scene', 'ambientIntensity', v)} envPreset={state.scene.environmentPreset} onUpdateEnvPreset={(v) => updateState('scene', 'environmentPreset', v)} />}
          {activeTab === 'effects' && <EffectsPanel effects={state.effects} onUpdateEffect={updateEffect} />}
          {activeTab === 'code' && <CodePanel state={state} />}
        </div>
      </div>
    </div>
  );
}

import React from 'react';
import { AppState, MaterialSettings, MaterialType, ModelType, ViewMode } from '../types';
import { Palette, Box, Layers, MousePointer2, Sparkles, Target, Grid3X3, Eye } from 'lucide-react';
import { MATERIAL_PRESETS_DATA } from '../constants';

interface SidebarProps {
  state: AppState;
  updateState: <K extends keyof AppState, S extends keyof AppState[K]>(
    category: K,
    key: S,
    value: AppState[K][S]
  ) => void;
  updateMaterial: <S extends keyof MaterialSettings>(key: S, value: MaterialSettings[S]) => void;
  setSelectedMaterialId: (id: string) => void;
}

const ControlGroup = ({ title, icon: Icon, children }: { title: string, icon: any, children?: React.ReactNode }) => (
  <div className="mb-10 last:mb-0">
    <div className="flex items-center gap-2 mb-5 text-slate-300">
      <div className="p-1.5 bg-slate-800 rounded-lg">
        <Icon size={14} className="text-blue-400" />
      </div>
      <h3 className="text-[10px] font-black uppercase tracking-[0.2em]">{title}</h3>
    </div>
    <div className="space-y-6">
      {children}
    </div>
  </div>
);

const Slider = ({ label, value, min, max, step, onChange, unit = "" }: any) => (
  <div className="group">
    <div className="flex justify-between items-center mb-1.5">
      <label className="text-[11px] font-medium text-slate-400 group-hover:text-slate-200 transition-colors">{label}</label>
      <span className="text-[10px] font-mono text-blue-400 bg-blue-500/10 px-1.5 py-0.5 rounded tabular-nums">{value}{unit}</span>
    </div>
    <input 
      type="range" 
      min={min} 
      max={max} 
      step={step} 
      value={value}
      onChange={(e) => onChange(parseFloat(e.target.value))}
      className="w-full h-1 bg-slate-800 rounded-full appearance-none cursor-pointer accent-blue-500 hover:accent-blue-400 transition-all"
    />
  </div>
);

const ColorPicker = ({ label, value, onChange }: any) => (
  <div className="flex justify-between items-center">
    <label className="text-[11px] font-medium text-slate-400">{label}</label>
    <div className="flex items-center gap-2">
      <span className="text-[10px] font-mono text-slate-500 uppercase">{value}</span>
      <input 
        type="color" 
        value={value}
        onChange={(e) => onChange(e.target.value)}
        className="w-5 h-5 rounded bg-transparent border-none cursor-pointer ring-1 ring-slate-700 overflow-hidden"
      />
    </div>
  </div>
);

const Toggle = ({ label, value, onChange }: any) => (
  <div className="flex justify-between items-center">
    <label className="text-[11px] font-medium text-slate-400">{label}</label>
    <button 
      onClick={() => onChange(!value)}
      className={`w-9 h-4.5 rounded-full transition-all relative cursor-pointer ${value ? 'bg-blue-600' : 'bg-slate-800'}`}
    >
      <div className={`absolute top-0.5 w-3.5 h-3.5 rounded-full bg-white transition-all shadow-sm ${value ? 'left-5' : 'left-0.5'}`} />
    </button>
  </div>
);

const Sidebar: React.FC<SidebarProps> = ({ state, updateState, updateMaterial, setSelectedMaterialId }) => {
  const activeMat = (state.materials[state.selectedMaterialId] || Object.values(state.materials)[0]) as MaterialSettings | undefined;

  const applyPreset = (presetData: any) => {
    Object.entries(presetData).forEach(([key, value]) => {
      updateMaterial(key as any, value as any);
    });
  };

  const materialTypes: MaterialType[] = ['basic', 'phong', 'lambert', 'standard', 'physical', 'toon', 'normal', 'depth', 'matcap'];
  const modelTypes: ModelType[] = ['icosahedron', 'sphere', 'box', 'torus', 'cylinder', 'cone', 'knot'];

  if (!activeMat) return <div className="text-slate-500 text-xs py-10 text-center">Initializing...</div>;

  const supportsColor = activeMat.type !== 'normal' && activeMat.type !== 'depth';
  const supportsEmissive = ['phong', 'lambert', 'standard', 'physical'].includes(activeMat.type);
  const supportsSpecular = activeMat.type === 'phong';
  const supportsPBR = ['standard', 'physical'].includes(activeMat.type);
  const supportsClearcoat = activeMat.type === 'physical';

  return (
    <div className="animate-in fade-in slide-in-from-right-4 duration-500 pb-10">

      <ControlGroup title="View Options" icon={Eye}>
        <div className="flex p-1 bg-slate-800 rounded-lg">
          {(['material', 'wireframe'] as ViewMode[]).map((mode) => (
            <button
              key={mode}
              onClick={() => updateState('scene', 'viewMode', mode)}
              className={`flex-1 py-2 text-[9px] font-black uppercase rounded-md transition-all cursor-pointer ${
                state.scene.viewMode === mode 
                ? 'bg-blue-600 text-white shadow-lg' 
                : 'text-slate-500 hover:text-slate-300'
              }`}
            >
              {mode === 'material' ? 'Material View' : 'Wireframe (Light)'}
            </button>
          ))}
        </div>
        <p className="text-[9px] text-slate-500 uppercase leading-relaxed text-center italic">
          {state.scene.viewMode === 'wireframe' ? 'Rendering performance optimized.' : 'Full shader quality active.'}
        </p>
      </ControlGroup>

      <div className="h-px bg-slate-800/50 my-8" />

      <ControlGroup title="Model Geometry" icon={Box}>
        <div className="grid grid-cols-4 gap-2">
          {modelTypes.map((type) => (
            <button
              key={type}
              onClick={() => updateState('scene', 'modelType', type)}
              className={`py-2 text-[8px] font-bold uppercase rounded-lg border transition-all cursor-pointer ${
                state.scene.modelType === type 
                ? 'bg-blue-600 border-blue-500 text-white shadow-lg' 
                : 'bg-slate-800 border-slate-700 text-slate-400 hover:text-white'
              }`}
            >
              {type}
            </button>
          ))}
        </div>
      </ControlGroup>

      <div className="h-px bg-slate-800/50 my-8" />

      {state.scene.viewMode === 'material' && (
        <div className="animate-in fade-in duration-300">
          <ControlGroup title="Material Focus" icon={Target}>
            <div className="space-y-3">
              <label className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Select Sub-Material</label>
              <select 
                value={state.selectedMaterialId}
                onChange={(e) => setSelectedMaterialId(e.target.value)}
                className="w-full bg-slate-800 border border-slate-700 text-slate-200 text-xs py-2 px-3 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all cursor-pointer"
              >
                {(Object.entries(state.materials) as [string, MaterialSettings][]).map(([id, mat]) => (
                  <option key={id} value={id}>{mat.name}</option>
                ))}
              </select>
              <Toggle 
                label="Override GLTF materials" 
                value={state.scene.overrideMaterials} 
                onChange={(v: boolean) => updateState('scene', 'overrideMaterials', v)} 
              />
            </div>
          </ControlGroup>

          <div className="h-px bg-slate-800/50 my-8" />

          <ControlGroup title="Material Engine" icon={MousePointer2}>
            <div className="grid grid-cols-3 gap-1 bg-slate-800 p-1 rounded-lg mb-6">
              {materialTypes.map((t) => (
                <button
                  key={t}
                  onClick={() => updateMaterial('type', t)}
                  className={`py-1.5 text-[8px] font-black uppercase rounded transition-all cursor-pointer ${
                    activeMat.type === t ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'
                  }`}
                >
                  {t}
                </button>
              ))}
            </div>
            <div className="grid grid-cols-2 gap-2">
              {Object.entries(MATERIAL_PRESETS_DATA).map(([name, data]) => (
                <button
                  key={name}
                  onClick={() => applyPreset(data)}
                  className="px-3 py-2 text-[9px] font-bold bg-slate-800 hover:bg-blue-600/20 border border-slate-700 hover:border-blue-500/50 rounded-lg transition-all text-slate-400 hover:text-white cursor-pointer"
                >
                  {name}
                </button>
              ))}
            </div>
          </ControlGroup>

          <div className="h-px bg-slate-800/50 my-8" />

          <ControlGroup title="Visual Properties" icon={Palette}>
            {supportsColor && (
              <ColorPicker label="Base Color" value={activeMat.color} onChange={(v: string) => updateMaterial('color', v)} />
            )}

            {supportsEmissive && (
              <div className="space-y-6 pt-4 border-t border-slate-800/50">
                <ColorPicker label="Emissive" value={activeMat.emissive} onChange={(v: string) => updateMaterial('emissive', v)} />
                <Slider label="Emissive Intensity" value={activeMat.emissiveIntensity} min={0} max={100} step={1} onChange={(v: number) => updateMaterial('emissiveIntensity', v)} />
              </div>
            )}

            {supportsSpecular && (
              <div className="space-y-6 pt-4 border-t border-slate-800">
                <h4 className="text-[9px] text-blue-400 uppercase font-black tracking-widest flex items-center gap-2">
                   <Sparkles size={10} /> Phong Highlights
                </h4>
                <ColorPicker label="Specular Color" value={activeMat.specular} onChange={(v: string) => updateMaterial('specular', v)} />
                <Slider label="Shininess" value={activeMat.shininess} min={0} max={100} step={1} onChange={(v: number) => updateMaterial('shininess', v)} />
              </div>
            )}

            {supportsPBR && (
              <div className="space-y-6 pt-4 border-t border-slate-800">
                <Slider label="Metalness" value={activeMat.metalness} min={0} max={1} step={0.01} onChange={(v: number) => updateMaterial('metalness', v)} />
                <Slider label="Roughness" value={activeMat.roughness} min={0} max={1} step={0.01} onChange={(v: number) => updateMaterial('roughness', v)} />
                <Slider label="Env Map Intensity" value={activeMat.envMapIntensity} min={0} max={5} step={0.1} onChange={(v: number) => updateMaterial('envMapIntensity', v)} />
              </div>
            )}

            <div className="pt-4 border-t border-slate-800 space-y-6">
              <Slider label="Opacity (Alpha)" value={activeMat.opacity} min={0} max={1} step={0.01} onChange={(v: number) => updateMaterial('opacity', v)} />
              <Toggle label="Wireframe" value={activeMat.wireframe} onChange={(v: boolean) => updateMaterial('wireframe', v)} />
            </div>
          </ControlGroup>

          {supportsClearcoat && (
            <>
              <div className="h-px bg-slate-800/50 my-8" />
              <ControlGroup title="Clearcoat & Transmission" icon={Layers}>
                <Slider label="Clearcoat" value={activeMat.clearcoat} min={0} max={1} step={0.01} onChange={(v: number) => updateMaterial('clearcoat', v)} />
                <Slider label="Clearcoat Roughness" value={activeMat.clearcoatRoughness} min={0} max={1} step={0.01} onChange={(v: number) => updateMaterial('clearcoatRoughness', v)} />
                <Slider label="Transmission" value={activeMat.transmission} min={0} max={1} step={0.01} onChange={(v: number) => updateMaterial('transmission', v)} />
                <Slider label="Thickness" value={activeMat.thickness} min={0} max={5} step={0.1} onChange={(v: number) => updateMaterial('thickness', v)} />
